import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../store/AuthContext';
import {
  LayoutDashboard, FileText, Zap, LogOut, Menu, X,
  ChevronDown, User, Sparkles,
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const [userMenuOpen, setUserMenuOpen] = useState(false);

  const navItems = [
    { label: 'Dashboard', icon: LayoutDashboard, path: '/dashboard' },
    { label: 'Generate', icon: Zap, path: '/generate' },
    { label: 'My Docs', icon: FileText, path: '/documents' },
  ];

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const isActive = (path) => location.pathname.startsWith(path);

  return (
    <nav style={{
      position: 'sticky',
      top: 0,
      zIndex: 100,
      background: 'rgba(10, 10, 15, 0.85)',
      backdropFilter: 'blur(20px)',
      borderBottom: '1px solid var(--border)',
    }}>
      <div className="container" style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        height: '64px',
      }}>
        {/* Logo */}
        <Link to="/dashboard" style={{
          display: 'flex',
          alignItems: 'center',
          gap: '10px',
          textDecoration: 'none',
        }}>
          <div style={{
            width: '34px', height: '34px',
            background: 'var(--accent)',
            borderRadius: '10px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            boxShadow: '0 0 20px var(--accent-glow)',
          }}>
            <Sparkles size={18} color="white" />
          </div>
          <span style={{
            fontSize: '18px',
            fontWeight: '800',
            color: 'var(--text-primary)',
            letterSpacing: '-0.03em',
          }}>
            AI<span style={{ color: 'var(--accent)' }}>Studio</span>
          </span>
        </Link>

        {/* Desktop Nav */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}
          className="desktop-nav">
          {navItems.map(({ label, icon: Icon, path }) => (
            <Link key={path} to={path} style={{
              display: 'flex',
              alignItems: 'center',
              gap: '6px',
              padding: '8px 14px',
              borderRadius: 'var(--radius)',
              fontSize: '14px',
              fontWeight: '600',
              color: isActive(path) ? 'var(--accent-light)' : 'var(--text-secondary)',
              background: isActive(path) ? 'rgba(108, 99, 255, 0.12)' : 'transparent',
              textDecoration: 'none',
              transition: 'all var(--transition)',
            }}
              onMouseEnter={e => {
                if (!isActive(path)) {
                  e.currentTarget.style.color = 'var(--text-primary)';
                  e.currentTarget.style.background = 'var(--bg-input)';
                }
              }}
              onMouseLeave={e => {
                if (!isActive(path)) {
                  e.currentTarget.style.color = 'var(--text-secondary)';
                  e.currentTarget.style.background = 'transparent';
                }
              }}
            >
              <Icon size={16} />
              {label}
            </Link>
          ))}
        </div>

        {/* User Menu */}
        <div style={{ position: 'relative' }}>
          <button
            className="btn btn-secondary"
            onClick={() => setUserMenuOpen(!userMenuOpen)}
            style={{ gap: '8px', padding: '8px 14px' }}
          >
            <div style={{
              width: '28px', height: '28px',
              background: 'var(--accent)',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '12px',
              fontWeight: '700',
              color: 'white',
              flexShrink: 0,
            }}>
              {user?.name?.[0]?.toUpperCase() || 'U'}
            </div>
            <span style={{ fontSize: '14px', fontWeight: '600', maxWidth: '120px',
              overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {user?.name?.split(' ')[0]}
            </span>
            <ChevronDown size={14} style={{
              transition: 'transform var(--transition)',
              transform: userMenuOpen ? 'rotate(180deg)' : 'none',
            }} />
          </button>

          {userMenuOpen && (
            <div style={{
              position: 'absolute',
              right: 0,
              top: 'calc(100% + 8px)',
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              borderRadius: 'var(--radius)',
              padding: '8px',
              minWidth: '200px',
              boxShadow: 'var(--shadow)',
              zIndex: 200,
            }}
              onMouseLeave={() => setUserMenuOpen(false)}
            >
              {/* User Info */}
              <div style={{
                padding: '10px 12px',
                borderBottom: '1px solid var(--border)',
                marginBottom: '8px',
              }}>
                <p style={{ fontSize: '13px', fontWeight: '700', color: 'var(--text-primary)' }}>
                  {user?.name}
                </p>
                <p style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '2px' }}>
                  {user?.email}
                </p>
                <span className={`badge badge-${user?.plan}`} style={{ marginTop: '6px' }}>
                  {user?.plan}
                </span>
              </div>

              {/* Usage */}
              <div style={{ padding: '6px 12px 10px', borderBottom: '1px solid var(--border)', marginBottom: '8px' }}>
                <p style={{ fontSize: '11px', color: 'var(--text-muted)', marginBottom: '6px' }}>
                  AI Generations
                </p>
                <div style={{
                  height: '4px', background: 'var(--bg-input)',
                  borderRadius: '2px', overflow: 'hidden',
                }}>
                  <div style={{
                    height: '100%',
                    width: `${Math.min(100, ((user?.generationsUsed || 0) / (user?.generationsLimit || 10)) * 100)}%`,
                    background: 'var(--accent)',
                    borderRadius: '2px',
                    transition: 'width 0.5s ease',
                  }} />
                </div>
                <p style={{ fontSize: '11px', color: 'var(--text-secondary)', marginTop: '4px' }}>
                  {user?.generationsUsed || 0} / {user?.generationsLimit || 10} used
                </p>
              </div>

              <button className="btn btn-ghost" style={{
                width: '100%', justifyContent: 'flex-start',
                fontSize: '13px', padding: '8px 12px', gap: '8px',
              }}
                onClick={handleLogout}
              >
                <LogOut size={14} />
                Sign Out
              </button>
            </div>
          )}
        </div>

        {/* Mobile Menu Toggle */}
        <button className="btn btn-ghost mobile-menu-btn"
          onClick={() => setMenuOpen(!menuOpen)}
          style={{ display: 'none' }}
        >
          {menuOpen ? <X size={20} /> : <Menu size={20} />}
        </button>
      </div>

      <style>{`
        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: flex !important; }
        }
      `}</style>
    </nav>
  );
};

export default Navbar;
